Hi @rwilkin!

The things you requested aren't built into tablesorter, but you can add them:

1. In the code below, the `replaceFilter` function hides the existing input and adds a reset button. It is called when the `filterInit` event is fired.
2. To add a select, you'll need the `setVal` and `addSelect` functions. They are called by using a delegated event binding on the table. The table cell is updated after the selection is made, or you can press <kbd>Esc</kbd> (twice, since the first time cancels the select and the second cancels the change) to revert the value.

Note: I am assuming the above two methods are applied to the same column. If not, change one of the two `' + column + '` within the appropriate function to the desired column.

Here is a ([demo](https://jsfiddle.net/Mottie/8crx66yk/)):

```js
$(function() {

  var $table = $('table'),
  options = ['abc 1', 'abc 2', 'abc 3'],
  column = 1; /* one-based index */

  function replaceFilter() {
    var $cell = $table.find('.tablesorter-filter-row td:nth-child(' + column + ')');
    $cell.find('input').hide();
    $('<button type="button">Reset</button>')
      .appendTo($cell)
      .click(function() {
        $table.trigger('filterReset');
      });
  }

  function setVal($cell, value) {
    $cell.text(value);
    $table.trigger('updateCell', $cell);
  }

  function addSelect($cell) {
    var originalValue = $cell.text();
    $cell.text('');
    $('<select>')
      .append('<option>' + options.join('</option><option>') + '</option>')
      .val(originalValue)
      .appendTo($cell)
      .one('keydown', function(event) {
        if (event.which === 27) {
          setVal($cell, originalValue);
        }
      })
      .one('change', function() {
        setVal($cell, $(this).val());
      });
  }

  $table
    .on('filterInit', replaceFilter)
    .on('click', 'td:nth-child(' + column + ')', function() {
      var $cell = $(this);
      if (!$cell.find('select').length) {
        addSelect($(this));
      }
    })
    .tablesorter({
      theme: 'blue',
      widgets: ['zebra', 'filter']
    });
});
```

