    proxy_scheme = proxy_string.split('://', 1)
    if proxy_string and proxy_scheme:
        proxy = {proxy_scheme : proxy_string}
    else:
        proxy = None
    tunein.TuneIn(config['tunein']['timeout'], proxy)

def TuneIn.__init__(..., proxies=None):
    if proxies:
        self._session.proxies = proxies
