Can we also have this for `rruleset`? I started work on this but ended up not needing it (yet) so I don't have a nice PR with tests etc., but I do have this implementation if anyone wants to pick it up.

```python
    def __str__(self):
        """
        Output a string that would generate this ``rruleset`` if passed to
        ``rrulestr(forceset=True)``.
        """
        def strftime(dt):
            return dt.strftime('%Y%m%dT%H%M%S')
        output = []
        for rrule in self._rrule:
            bits = str(rrule).splitlines()
            if rrule._dtstart:
                output.append(bits.pop(0))
            output.append('RRULE:%s' % bits[0])
        if self._rdate:
            output.append(
                'RDATE:%s' % ','.join(strftime(dt for dt in self._rdate)))
        for exrule in self._exrule:
            bits = str(exrule).splitlines()
            if exrule._dtstart:
                output.append(bits.pop(0))
            output.append('EXRULE:%s' % bits[0])
        if self._exdate:
            output.append(
                'EXDATE:%s' % ','.join(strftime(dt for dt in self._exdate)))
            output.append('EXDATE:%s' % ','.join(self._exdate))
        return '\n'.join(output)
```

